import{B as e,Q as t,s as n,z as r}from"./chunks/framework.GF8LbaeE.js";var i=JSON.parse(`{"title":"Entities","description":"","frontmatter":{},"headers":[],"relativePath":"guide/entities.md","filePath":"guide/entities.md"}`),a={name:`guide/entities.md`};function o(n,i,a,o,s,c){return t(),r(`div`,null,[...i[0]||=[e(`<h1 id="entities" tabindex="-1">Entities <a class="header-anchor" href="#entities" aria-label="Permalink to &quot;Entities&quot;">​</a></h1><p>Welcome to the Entities guide. This documentation is automatically generated from the latest game features.</p><h2 id="tag-teams" tabindex="-1">Tag Teams <a class="header-anchor" href="#tag-teams" aria-label="Permalink to &quot;Tag Teams&quot;">​</a></h2><p>Track formal tag team partnerships. Teams often have their own specific finishing moves and shared history in the Tag Team division.</p><p><img src="/all-time-wrestling-rpg/screenshots/entity-teams.png" alt="Tag Teams"></p><hr><h2 id="create-championship-title" tabindex="-1">Create Championship Title <a class="header-anchor" href="#create-championship-title" aria-label="Permalink to &quot;Create Championship Title&quot;">​</a></h2><p>Define a new championship: enter the name, select the tier and championship type, optionally restrict by gender, and upload a belt image. Once saved the title appears in the list and becomes available for match booking.</p><p><img src="/all-time-wrestling-rpg/screenshots/title-create-dialog.png" alt="Create Championship Title"></p><hr><h2 id="championship-titles" tabindex="-1">Championship Titles <a class="header-anchor" href="#championship-titles" aria-label="Permalink to &quot;Championship Titles&quot;">​</a></h2><p>Manage every championship belt in the promotion. Each title has a configurable tier (controls contender eligibility), championship type, and gender restriction. The Challengers column lets bookers assign contenders inline without leaving the list view.</p><p><img src="/all-time-wrestling-rpg/screenshots/title-list-overview.png" alt="Championship Titles"></p><hr><h2 id="seasons" tabindex="-1">Seasons <a class="header-anchor" href="#seasons" aria-label="Permalink to &quot;Seasons&quot;">​</a></h2><p>Configure and track game seasons. Seasons group shows together and define the journey toward major year-end events.</p><p><img src="/all-time-wrestling-rpg/screenshots/entity-seasons.png" alt="Seasons"></p><hr><h2 id="championships" tabindex="-1">Championships <a class="header-anchor" href="#championships" aria-label="Permalink to &quot;Championships&quot;">​</a></h2><p>Manage the various titles across the promotion. From World Championships to regional belts, track current champions and the prestige of each title.</p><p><img src="/all-time-wrestling-rpg/screenshots/entity-titles.png" alt="Championships"></p><hr><h2 id="factions" tabindex="-1">Factions <a class="header-anchor" href="#factions" aria-label="Permalink to &quot;Factions&quot;">​</a></h2><p>Manage powerful wrestling groups. Factions bring together multiple wrestlers under a single banner, creating complex storylines and alliance-based rivalries.</p><p><img src="/all-time-wrestling-rpg/screenshots/entity-factions.png" alt="Factions"></p><hr>`,26)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};